 93→    // ----------------------------------------------------------------
 94→
 95→    public function batchCheck(Request $request): JsonResponse
 96→    {
 97→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
 98→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
