120→    // ----------------------------------------------------------------
121→
122→    public function save(Request $request): JsonResponse
123→    {
124→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
125→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
