139→        [$reporterIds, $ccIds] = $service->resolveReporterAndCcIds($sfuserId, $weekStart, $weekEnd);
140→
141→        $result = $service->saveSummary([
142→            'sfuser_id' => $sfuserId,
143→            'week_start' => $weekStart,
144→            'week_end' => $weekEnd,
145→            'reporter_ids' => $reporterIds,
146→            'cc_ids' => $ccIds,
147→            'content' => $input['content'] ?? '',
148→            'token' => $input['authorized_token'] ?? '',
149→            'submit_days' => $input['submit_days'] ?? 0,
150→            'total_chars' => $input['total_chars'] ?? 0,
