169→    public function get(Request $request): JsonResponse
170→    {
171→        $currentSfuserId = Arr::get($request->input('sfuser_info'), 'id');
172→        if (!DailyReportService::inAiWhitelist($currentSfuserId)) {
173→            return $this->responseJsonFail('无权限');
174→        }
175→
176→        $targetSfuserId = $request->input('sfuser_id');
177→        $weekStart = $request->input('week_start');
178→
179→        $summary = DailyReportWeeklySummary::where('sfuser_id', $targetSfuserId)
180→            ->where('week_start', $weekStart)
181→            ->first();
182→
183→        if (empty($summary)) {
184→            return $this->responseJsonSuccess(['summary' => null]);
185→        }
186→
187→        // 权限校验：当前用户必须是 owner 或在 reporter_ids/cc_ids 中
188→        $reporterIds = array_filter(explode(',', $summary->reporter_ids));
189→        $ccIds = array_filter(explode(',', $summary->cc_ids));
190→        $allowed = $currentSfuserId == $targetSfuserId
191→            || in_array($currentSfuserId, $reporterIds)
192→            || in_array($currentSfuserId, $ccIds);
193→
194→        if (!$allowed) {
195→            \Log::warn('[lbl][0423-周摘要][Get][DENIED] 无权限查看周摘要', [
196→                'current_sfuser_id' => $currentSfuserId,
197→                'target_sfuser_id' => $targetSfuserId,
198→                'week_start' => $weekStart,
199→            ]);
200→
201→            return $this->responseJsonFail('无权限查看该周摘要');
202→        }
203→
204→        return $this->responseJsonSuccess([
205→            'summary' => [
206→                'id' => $summary->id,
207→                'sfuser_id' => $summary->sfuser_id,
208→                'week_start' => $summary->week_start,
209→                'week_end' => $summary->week_end,
210→                'content' => $summary->content,
211→                'submit_days' => $summary->submit_days,
212→                'total_chars' => $summary->total_chars,
213→                'created_at' => $summary->created_at,
214→                'updated_at' => $summary->updated_at,
215→            ],
216→            'decrypt_config' => [
217→                'tokens' => [$summary->token],
218→            ],
219→        ]);
220→    }
