266→
267→    public function extractProjects(Request $request): JsonResponse
268→    {
269→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
270→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
271→            return $this->responseJsonFail('无权限');
