277→            'sfuser_id' => $sfuserId,
278→            'summary_chars' => mb_strlen($summaryText),
279→        ]);
280→
281→        return $this->responseJsonSuccess([
282→            'message' => $summaryText,
283→            'ai_analysis_config' => [
284→                'system_prompt' => self::PROJECT_NER_PROMPT,
285→                'target_field' => 'message',
286→                'output_field' => 'ai_result',
287→            ],
288→        ]);
289→    }
290→
291→    // ----------------------------------------------------------------
292→    // 保存 Room + Tunnel（项目索引）
293→    // ----------------------------------------------------------------
294→
295→    public function saveProjects(Request $request): JsonResponse
296→    {
297→        $currentSfuserId = Arr::get($request->input('sfuser_info'), 'id');
298→        if (!DailyReportService::inAiWhitelist($currentSfuserId)) {
299→            return $this->responseJsonFail('无权限');
300→        }
301→
302→        $sfuserId = $request->input('sfuser_id');
303→        $weekStart = $request->input('week_start');
304→        $projectNames = $request->input('project_names', []);
305→
306→        $service = WeeklySummaryService::app();
307→        $roomsCreated = 0;
308→        $tunnelsUpdated = 0;
309→
310→        foreach ($projectNames as $name) {
311→            $name = trim($name);
312→            if (empty($name)) {
313→                continue;
314→            }
315→
316→            $existsBefore = DailyReportAiRoom::where('project_name', $name)->exists();
317→            $roomId = $service->findOrCreateRoom($name);
318→            if ($roomId <= 0) {
319→                continue;
320→            }
321→
322→            if (!$existsBefore) {
323→                $roomsCreated++;
324→            }
325→
326→            $service->saveTunnel($roomId, $sfuserId, $weekStart);
327→            $tunnelsUpdated++;
328→        }
329→
330→        \Log::info('[lbl][0423-周摘要][SaveProjects] done', [
331→            'sfuser_id' => $sfuserId,
332→            'week_start' => $weekStart,
333→            'projects' => count($projectNames),
334→            'rooms_created' => $roomsCreated,
335→            'tunnels_updated' => $tunnelsUpdated,
336→        ]);
337→
338→        return $this->responseJsonSuccess([
339→            'rooms_created' => $roomsCreated,
340→            'tunnels_updated' => $tunnelsUpdated,
341→        ]);
342→    }
343→
344→}
