  3→namespace App\Service;
  4→
  5→use App\Models\DailyReport;
  6→use App\Models\DailyReportAiRoom;
  7→use App\Models\DailyReportAiTunnel;
  8→use App\Models\DailyReportWeeklySummary;
  9→use App\Service\Traits\TService;
 10→use Carbon\Carbon;
 11→use Illuminate\Support\Facades\DB;
 12→use Illuminate\Support\Facades\Log;
 13→
 14→class WeeklySummaryService
 15→{
 16→    use TService;
 17→
 18→    /**
 19→     * 计算 ISO 周边界（周一~周日）.
 20→     *
 21→     * @return array{week_start: string, week_end: string}
 22→     */
 23→    public function getWeekBounds(string $date): array
 24→    {
 25→        $carbon = Carbon::parse($date);
 26→        $weekStart = $carbon->copy()->startOfWeek(Carbon::MONDAY)->toDateString();
 27→        $weekEnd = $carbon->copy()->endOfWeek(Carbon::SUNDAY)->toDateString();
 28→
 29→        return ['week_start' => $weekStart, 'week_end' => $weekEnd];
 30→    }
 31→
 32→    /**
 33→     * 从该用户本周已提交的日报中，取 reporter_ids 和 cc_ids 的并集.
 34→     *
 35→     * @return array{0: string, 1: string} [reporter_ids, cc_ids]
 36→     */
 37→    public function resolveReporterAndCcIds(int $sfuserId, string $weekStart, string $weekEnd): array
 38→    {
 39→        $reports = DailyReport::where('sfuser_id', $sfuserId)
 40→            ->where('report_date', '>=', $weekStart)
 41→            ->where('report_date', '<=', $weekEnd)
 42→            ->where('status', DailyReport::STATUS_COMMITTED)
 43→            ->select(['reporter_ids', 'cc_ids'])
 44→            ->get();
 45→
 46→        $reporterIds = [];
 47→        $ccIds = [];
 48→        foreach ($reports as $report) {
 49→            foreach (array_filter(explode(',', $report->reporter_ids)) as $id) {
 50→                $reporterIds[(int) $id] = true;
 51→            }
 52→            foreach (array_filter(explode(',', $report->cc_ids)) as $id) {
 53→                $ccIds[(int) $id] = true;
 54→            }
 55→        }
 56→
 57→        return [
 58→            implode(',', array_keys($reporterIds)),
 59→            implode(',', array_keys($ccIds)),
 60→        ];
 61→    }
 62→
 63→    /**
 64→     * 查找或创建 Room，优先精确匹配 project_name，再模糊匹配 aliases.
 65→     */
 66→    public function findOrCreateRoom(string $projectName): int
 67→    {
 68→        $projectName = trim($projectName);
 69→        if (empty($projectName)) {
 70→            return 0;
 71→        }
 72→
 73→        // 精确匹配 project_name
 74→        $room = DailyReportAiRoom::where('project_name', $projectName)
 75→            ->where('status', DailyReportAiRoom::STATUS_ACTIVE)
 76→            ->first();
 77→        if ($room) {
 78→            return $room->id;
 79→        }
 80→
 81→        // 模糊匹配 aliases（JSON 数组包含检查）
 82→        $allRooms = DailyReportAiRoom::where('status', DailyReportAiRoom::STATUS_ACTIVE)->get();
 83→        foreach ($allRooms as $room) {
 84→            $aliases = $room->aliases ?? [];
 85→            if (in_array($projectName, $aliases, true)) {
 86→                return $room->id;
 87→            }
 88→        }
 89→
 90→        // 未找到，创建新 Room
 91→        $newRoom = DailyReportAiRoom::create([
 92→            'project_name' => $projectName,
 93→            'aliases' => [],
 94→        ]);
 95→
 96→        Log::info('[lbl][0423-周摘要][Room] 新建项目', [
 97→            'room_id' => $newRoom->id,
 98→            'project_name' => $projectName,
 99→        ]);
100→
101→        return $newRoom->id;
102→    }
103→
104→    /**
105→     * 保存人员-项目关联（Tunnel）.
106→     */
107→    public function saveTunnel(int $roomId, int $sfuserId, string $weekStart): void
108→    {
109→        if ($roomId <= 0) {
110→            return;
111→        }
112→
113→        DailyReportAiTunnel::insertOrIgnore([
114→            'room_id' => $roomId,
115→            'sfuser_id' => $sfuserId,
116→            'week_start' => $weekStart,
117→            'created_at' => now(),
118→        ]);
119→    }
120→
121→    /**
122→     * 保存周摘要（upsert）.
123→     *
124→     * @return array{id: int, created: bool}
125→     */
126→    public function saveSummary(array $data): array
127→    {
128→        $sfuserId = $data['sfuser_id'];
129→        $weekStart = $data['week_start'];
130→
131→        $existing = DailyReportWeeklySummary::where('sfuser_id', $sfuserId)
132→            ->where('week_start', $weekStart)
133→            ->first();
134→
135→        $summaryData = [
136→            'sfuser_id' => $sfuserId,
137→            'week_start' => $weekStart,
138→            'week_end' => $data['week_end'],
139→            'reporter_ids' => $data['reporter_ids'] ?? '',
140→            'cc_ids' => $data['cc_ids'] ?? '',
141→            'content' => $data['content'],
142→            'token' => $data['token'] ?? '',
143→            'submit_days' => $data['submit_days'] ?? 0,
144→            'total_chars' => $data['total_chars'] ?? 0,
145→        ];
146→
147→        $created = false;
148→        if ($existing) {
149→            $existing->update($summaryData);
150→            $summaryId = $existing->id;
151→        } else {
152→            $summary = DailyReportWeeklySummary::create($summaryData);
153→            $summaryId = $summary->id;
154→            $created = true;
155→        }
156→
157→        // 替换来源日报关联
158→        $reportIds = $data['report_ids'] ?? [];
159→        if (!empty($reportIds)) {
160→            DB::table('daily_report_weekly_summary_report_ids')
161→                ->where('summary_id', $summaryId)
162→                ->delete();
163→
164→            $rows = array_map(fn ($rid) => [
165→                'summary_id' => $summaryId,
166→                'report_id' => $rid,
167→            ], $reportIds);
168→
169→            DB::table('daily_report_weekly_summary_report_ids')->insert($rows);
170→        }
171→
172→        return ['id' => $summaryId, 'created' => $created];
173→    }
174→}
